noncompliant:
// Noncompliant: Base class handler before derived class
class BaseException { };
class DerivedException : public BaseException { };

void function() {
    try {
        // some code that may throw
    }
    catch (BaseException &b) {  // Noncompliant: catches derived too
        // handle base exception
    }
    catch (DerivedException &d) {  // Will never be reached
        // handle derived exception
    }
}

// Another noncompliant example
class A { };
class B : public A { };
class C : public B { };

void test() {
    try {
        // code
    }
    catch (A& a) {  // Catches everything
        // handle A
    }
    catch (B& b) {  // Never reached
        // handle B
    }
    catch (C& c) {  // Never reached
        // handle C
    }
}

compliant:
// Compliant: Most derived class handler first
class BaseException { };
class DerivedException : public BaseException { };

void function() {
    try {
        // some code that may throw
    }
    catch (DerivedException &d) {  // Most derived first
        // handle derived exception
    }
    catch (BaseException &b) {  // Base class after derived
        // handle base exception
    }
}

// Another compliant example
class A { };
class B : public A { };
class C : public B { };

void test() {
    try {
        // code
    }
    catch (C& c) {  // Most derived first
        // handle C
    }
    catch (B& b) {  // Then intermediate
        // handle B
    }
    catch (A& a) {  // Base class last
        // handle A
    }
}
